mapper.update:
UPDATE stocks
SET status = #{status}
WHERE id = #{id}
  AND status = 'IN_STOCK'

mapper.delete:
DELETE FROM stocks
WHERE item_id = #{itemId}
  AND box_id  = #{boxId}
  AND status  = 'IN_STOCK'

DELETE FROM stocks
WHERE item_id  = #{itemId}
  AND shelf_id = #{shelfId}
  AND box_id IS NULL
  AND status   = 'IN_STOCK'

DELETE FROM stocks
WHERE item_id  = #{itemId}
  AND space_id = #{spaceId}
  AND shelf_id IS NULL
  AND status   = 'IN_STOCK'
